class Solution:
    def mirrorReflection(self, p, q):
        t = 0
        v = 0
        while True:
            t += 1
            v += q
            if v % p == 0:
                break
        if t % 2 == 0:
            return 2
        rows = v // p
        return 0 if rows % 2 == 0 else 1

