var mirrorReflection = function(p, q) {
    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
    const g = gcd(p, q);
    p = Math.floor(p / g);
    q = Math.floor(q / g);
    if (p % 2 === 0) return 2;
    return q % 2 === 0 ? 0 : 1;
};
